import React, { useState } from 'react';
import { 
  Star, 
  Heart, 
  Share2, 
  Bookmark, 
  TrendingUp, 
  Users, 
  Brain, 
  Trophy,
  Play,
  X,
  Loader
} from 'lucide-react';

// Mock AuthContext for demo
const AuthContext = React.createContext({
  isAuthenticated: true,
});

// Mock services
const rateMovie = async (data) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ rating: data.rating }), 500);
  });
};

const checkUserRating = async (movieId) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ has_rated: false }), 300);
  });
};

const MovieCard = ({ 
  movie = {
    id: 1,
    title: "Inception",
    year: 2010,
    poster_url: "https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop",
    avg_rating: 4.5,
    rating_count: 1247,
    plot: "A thief who enters the dreams of others to steal their secrets from their subconscious gets a chance to have his criminal record erased in exchange for one final job.",
    genres: ["Action", "Sci-Fi", "Thriller", "Drama"],
    recommendation_score: 0.85
  }, 
  showRecommendationScore = true, 
  recommendationSources = ['collaborative', 'content'], 
  onRatingUpdate = null 
}) => {
  const { isAuthenticated } = React.useContext(AuthContext);
  const [showQuickRate, setShowQuickRate] = useState(false);
  const [quickRating, setQuickRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [isRating, setIsRating] = useState(false);
  const [userRating, setUserRating] = useState(null);
  const [isHovered, setIsHovered] = useState(false);
  const [isFavorited, setIsFavorited] = useState(false);

  React.useEffect(() => {
    if (isAuthenticated && movie.id) {
      fetchUserRating();
    }
  }, [isAuthenticated, movie.id]);

  const fetchUserRating = async () => {
    try {
      const ratingData = await checkUserRating(movie.id);
      if (ratingData.has_rated) {
        setUserRating(ratingData.rating);
      }
    } catch (error) {
      // User hasn't rated this movie, which is fine
    }
  };

  const handleQuickRate = async (rating) => {
    if (!isAuthenticated) return;

    setIsRating(true);
    try {
      const ratingData = await rateMovie({
        movie_id: movie.id,
        rating: rating,
        review: ''
      });

      setUserRating({ rating: ratingData.rating });
      setShowQuickRate(false);

      if (onRatingUpdate) {
        onRatingUpdate(movie.id, rating);
      }
    } catch (error) {
      console.error('Error rating movie:', error);
    } finally {
      setIsRating(false);
    }
  };

  const renderStars = (rating, interactive = false, size = 'small') => {
    const stars = [];
    const maxStars = 5;
    const displayRating = interactive ? (hoverRating || quickRating) : rating;
    const sizeMap = { small: 16, medium: 20, large: 24 };
    const iconSize = sizeMap[size];

    for (let i = 1; i <= maxStars; i++) {
      const filled = i <= displayRating;
      stars.push(
        <button
          key={i}
          type="button"
          className={`transition-all duration-200 ${interactive ? 'hover:scale-110 cursor-pointer' : 'cursor-default'} p-0 border-0 bg-transparent`}
          onClick={interactive ? () => {
            setQuickRating(i);
            handleQuickRate(i);
          } : undefined}
          onMouseEnter={interactive ? () => setHoverRating(i) : undefined}
          onMouseLeave={interactive ? () => setHoverRating(0) : undefined}
        >
          <Star 
            size={iconSize} 
            fill={filled ? '#facc15' : 'transparent'}
            color={filled ? '#facc15' : 'rgba(255, 255, 255, 0.5)'}
            style={{ filter: filled ? 'drop-shadow(0 1px 2px rgba(0, 0, 0, 0.1))' : 'none' }}
          />
        </button>
      );
    }

    return <div style={{ display: 'flex', gap: '2px', alignItems: 'center' }}>{stars}</div>;
  };

  const getRecommendationBadge = () => {
    if (!showRecommendationScore || !recommendationSources || recommendationSources.length === 0) {
      return null;
    }

    const isCollaborative = recommendationSources.includes('collaborative');
    const isContent = recommendationSources.includes('content');
    const isBoth = isCollaborative && isContent;

    const badgeConfig = isBoth
      ? { text: 'Perfect Match', Icon: Trophy, bgColor: 'linear-gradient(135deg, #4ade80, #22c55e)' }
      : isCollaborative
        ? { text: 'Similar Users', Icon: Users, bgColor: 'linear-gradient(135deg, #60a5fa, #3b82f6)' }
        : { text: 'Your Taste', Icon: Brain, bgColor: 'linear-gradient(135deg, #fbbf24, #f59e0b)' };

    return (
      <div 
        style={{
          position: 'absolute',
          top: '12px',
          right: '12px',
          zIndex: 30,
          padding: '4px 8px',
          borderRadius: '12px',
          fontSize: '11px',
          fontWeight: '600',
          color: 'white',
          background: badgeConfig.bgColor,
          backdropFilter: 'blur(8px)',
          border: '1px solid rgba(255, 255, 255, 0.2)',
          display: 'flex',
          alignItems: 'center',
          gap: '4px',
          boxShadow: '0 4px 12px rgba(0, 0, 0, 0.25)',
        }}
      >
        <badgeConfig.Icon size={12} />
        {badgeConfig.text}
      </div>
    );
  };

  const formatYear = (year) => {
    return year ? `(${year})` : '';
  };

  const truncateTitle = (title, maxLength = 30) => {
    if (!title) return '';
    return title.length > maxLength ? `${title.substring(0, maxLength)}...` : title;
  };

  const cardStyle = {
    position: 'relative',
    height: '100%',
    display: 'flex',
    flexDirection: 'column',
    background: isHovered 
      ? 'linear-gradient(135deg, rgba(168, 85, 247, 0.15) 0%, rgba(236, 72, 153, 0.15) 100%)'
      : 'rgba(255, 255, 255, 0.1)',
    backdropFilter: 'blur(20px)',
    border: '1px solid rgba(255, 255, 255, 0.2)',
    borderRadius: '16px',
    overflow: 'hidden',
    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
    transform: isHovered ? 'translateY(-8px) scale(1.02)' : 'translateY(0) scale(1)',
    boxShadow: isHovered 
      ? '0 25px 50px rgba(0, 0, 0, 0.3), 0 0 30px rgba(168, 85, 247, 0.2)' 
      : '0 8px 25px rgba(0, 0, 0, 0.15)',
  };

  return (
    <div 
      style={cardStyle}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {getRecommendationBadge()}

      {/* Movie Poster */}
      <div style={{ position: 'relative', aspectRatio: '2/3', overflow: 'hidden' }}>
        <img
          src={movie.poster_url || 'https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop'}
          alt={movie.title}
          style={{
            width: '100%',
            height: '100%',
            objectFit: 'cover',
            transition: 'transform 0.3s ease',
            transform: isHovered ? 'scale(1.05)' : 'scale(1)',
          }}
          onError={(e) => {
            e.target.src = 'https://images.unsplash.com/photo-1489599735734-79b4ba5c18a6?w=300&h=450&fit=crop';
          }}
        />

        {/* Overlay with hover effects */}
        <div 
          style={{
            position: 'absolute',
            inset: '0',
            background: 'linear-gradient(to bottom, transparent 0%, transparent 50%, rgba(0, 0, 0, 0.9) 100%)',
            transition: 'opacity 0.3s ease',
            opacity: isHovered ? 1 : 0,
          }}
        >
          <div style={{ 
            position: 'absolute', 
            inset: '0', 
            display: 'flex', 
            flexDirection: 'column', 
            justifyContent: 'space-between',
            padding: '16px'
          }}>
            {/* Top actions */}
            <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end' }}>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setIsFavorited(!isFavorited);
                }}
                style={{
                  padding: '8px',
                  background: 'rgba(255, 255, 255, 0.2)',
                  backdropFilter: 'blur(8px)',
                  borderRadius: '50%',
                  color: isFavorited ? '#ef4444' : 'white',
                  border: 'none',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                }}
                title="Add to favorites"
              >
                <Heart size={16} fill={isFavorited ? '#ef4444' : 'none'} />
              </button>
              <button
                style={{
                  padding: '8px',
                  background: 'rgba(255, 255, 255, 0.2)',
                  backdropFilter: 'blur(8px)',
                  borderRadius: '50%',
                  color: 'white',
                  border: 'none',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                }}
                title="Share"
              >
                <Share2 size={16} />
              </button>
            </div>

            {/* Bottom info */}
            <div style={{
              transform: isHovered ? 'translateY(0)' : 'translateY(20px)',
              transition: 'transform 0.3s ease',
            }}>
              {/* Rating */}
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
                {renderStars(movie.avg_rating || 0)}
                <span style={{ color: 'white', fontWeight: '600', fontSize: '14px' }}>
                  {movie.avg_rating ? movie.avg_rating.toFixed(1) : 'No rating'}
                </span>
              </div>

              {/* Plot preview */}
              {movie.plot && (
                <p style={{ 
                  color: 'rgba(255, 255, 255, 0.9)', 
                  fontSize: '12px', 
                  lineHeight: '1.5',
                  marginBottom: '12px',
                  display: '-webkit-box',
                  WebkitLineClamp: 3,
                  WebkitBoxOrient: 'vertical',
                  overflow: 'hidden',
                  margin: '0 0 12px 0',
                }}>
                  {movie.plot}
                </p>
              )}

              {/* Quick actions */}
              <div style={{ display: 'flex', gap: '8px' }}>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    // Navigate to movie details
                  }}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '4px',
                    padding: '6px 12px',
                    background: 'linear-gradient(135deg, #a855f7, #ec4899)',
                    color: 'white',
                    border: 'none',
                    borderRadius: '8px',
                    fontSize: '12px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    transition: 'all 0.2s ease',
                  }}
                >
                  <Play size={12} />
                  Details
                </button>
                <button 
                  style={{
                    padding: '6px',
                    background: 'rgba(255, 255, 255, 0.2)',
                    backdropFilter: 'blur(8px)',
                    borderRadius: '8px',
                    color: 'white',
                    border: 'none',
                    cursor: 'pointer',
                    transition: 'all 0.2s ease',
                  }}
                >
                  <Bookmark size={14} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Card Content */}
      <div style={{ 
        flex: '1', 
        display: 'flex', 
        flexDirection: 'column', 
        gap: '12px', 
        padding: '16px',
        position: 'relative',
        zIndex: 2,
      }}>
        {/* Title and Year */}
        <div>
          <button
            onClick={() => {
              // Navigate to movie details
            }}
            style={{
              display: 'block',
              textAlign: 'left',
              width: '100%',
              background: 'none',
              border: 'none',
              padding: '0',
              cursor: 'pointer',
            }}
          >
            <h3 
              style={{
                fontWeight: '700',
                color: 'white',
                fontSize: '16px',
                lineHeight: '1.2',
                transition: 'color 0.2s ease',
                margin: '0',
              }}
              title={movie.title}
            >
              {truncateTitle(movie.title)}
            </h3>
          </button>
          <p style={{ 
            color: 'rgba(255, 255, 255, 0.7)', 
            fontSize: '14px', 
            marginTop: '2px',
            margin: '2px 0 0 0',
          }}>
            {formatYear(movie.year)}
          </p>
        </div>

        {/* User's rating if available */}
        {userRating && (
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            padding: '12px',
            background: 'rgba(168, 85, 247, 0.2)',
            border: '1px solid rgba(168, 85, 247, 0.3)',
            borderRadius: '12px',
            backdropFilter: 'blur(8px)',
          }}>
            <span style={{ color: '#c084fc', fontWeight: '600', fontSize: '12px' }}>Your rating:</span>
            {renderStars(userRating.rating)}
          </div>
        )}

        {/* Quick rating for authenticated users */}
        {isAuthenticated && !userRating && (
          <div style={{ marginTop: 'auto' }}>
            {!showQuickRate ? (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setShowQuickRate(true);
                }}
                disabled={isRating}
                style={{
                  width: '100%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px',
                  padding: '10px',
                  background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '12px',
                  fontSize: '14px',
                  fontWeight: '600',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                  opacity: isRating ? 0.6 : 1,
                }}
              >
                <Star size={16} />
                Quick Rate
              </button>
            ) : (
              <div
                onClick={(e) => e.stopPropagation()}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '12px',
                  padding: '12px',
                  background: 'rgba(255, 255, 255, 0.1)',
                  border: '1px solid rgba(255, 255, 255, 0.2)',
                  borderRadius: '12px',
                  backdropFilter: 'blur(8px)',
                }}
              >
                <span style={{ color: 'rgba(255, 255, 255, 0.8)', fontWeight: '600', fontSize: '12px' }}>Rate:</span>
                {renderStars(quickRating, true)}
                <button
                  onClick={() => setShowQuickRate(false)}
                  style={{
                    marginLeft: 'auto',
                    color: '#f87171',
                    background: 'none',
                    border: 'none',
                    cursor: 'pointer',
                    padding: '4px',
                  }}
                >
                  <X size={16} />
                </button>
              </div>
            )}
          </div>
        )}

        {/* Movie metadata */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', marginTop: 'auto' }}>
          {movie.rating_count > 0 && (
            <span style={{ color: 'rgba(255, 255, 255, 0.6)', fontSize: '12px' }}>
              {movie.rating_count} rating{movie.rating_count !== 1 ? 's' : ''}
            </span>
          )}

          {showRecommendationScore && movie.recommendation_score && (
            <div style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
              <TrendingUp size={14} color="#4ade80" />
              <span style={{ color: '#4ade80', fontWeight: '600', fontSize: '12px' }}>
                {(movie.recommendation_score * 100).toFixed(0)}% Match
              </span>
            </div>
          )}
        </div>

        {/* Genres */}
        {movie.genres && movie.genres.length > 0 && (
          <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap', marginTop: '8px' }}>
            {movie.genres.slice(0, 3).map(genre => (
              <span
                key={genre}
                style={{
                  padding: '4px 8px',
                  background: 'rgba(59, 130, 246, 0.2)',
                  color: '#93c5fd',
                  border: '1px solid rgba(59, 130, 246, 0.3)',
                  borderRadius: '8px',
                  fontSize: '11px',
                  fontWeight: '500',
                }}
              >
                {genre}
              </span>
            ))}
            {movie.genres.length > 3 && (
              <span style={{ 
                color: 'rgba(255, 255, 255, 0.5)', 
                fontSize: '11px', 
                fontStyle: 'italic',
                alignSelf: 'center',
              }}>
                +{movie.genres.length - 3} more
              </span>
            )}
          </div>
        )}
      </div>

      {/* Loading overlay for rating */}
      {isRating && (
        <div style={{
          position: 'absolute',
          inset: '0',
          background: 'rgba(255, 255, 255, 0.1)',
          backdropFilter: 'blur(4px)',
          borderRadius: '16px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 50,
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            color: 'white',
          }}>
            <Loader size={20} color="#a855f7" style={{ animation: 'spin 1s linear infinite' }} />
            <span style={{ fontWeight: '500', fontSize: '14px' }}>Rating...</span>
          </div>
        </div>
      )}

      {/* Decorative elements */}
      <div style={{
        position: 'absolute',
        top: '-16px',
        left: '-16px',
        width: '96px',
        height: '96px',
        background: 'linear-gradient(135deg, rgba(168, 85, 247, 0.2), rgba(236, 72, 153, 0.2))',
        borderRadius: '50%',
        filter: 'blur(48px)',
        zIndex: -1,
      }} />
      <div style={{
        position: 'absolute',
        bottom: '-16px',
        right: '-16px',
        width: '128px',
        height: '128px',
        background: 'linear-gradient(135deg, rgba(59, 130, 246, 0.2), rgba(168, 85, 247, 0.2))',
        borderRadius: '50%',
        filter: 'blur(48px)',
        zIndex: -1,
      }} />
    </div>
  );
};

// Demo wrapper with dark background
export default function ModernMovieCardDemo() {
  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #0f172a 100%)',
      padding: '32px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      position: 'relative',
      overflow: 'hidden',
    }}>
      {/* Animated background elements */}
      <div style={{
        position: 'absolute',
        top: '25%',
        left: '25%',
        width: '384px',
        height: '384px',
        background: 'rgba(168, 85, 247, 0.1)',
        borderRadius: '50%',
        filter: 'blur(48px)',
        animation: 'pulse 2s ease-in-out infinite',
      }} />
      <div style={{
        position: 'absolute',
        bottom: '25%',
        right: '25%',
        width: '384px',
        height: '384px',
        background: 'rgba(59, 130, 246, 0.1)',
        borderRadius: '50%',
        filter: 'blur(48px)',
        animation: 'pulse 2s ease-in-out infinite 1s',
      }} />
      <div style={{
        position: 'absolute',
        top: '50%',
        left: '50%',
        transform: 'translate(-50%, -50%)',
        width: '500px',
        height: '500px',
        background: 'linear-gradient(135deg, rgba(168, 85, 247, 0.05), rgba(236, 72, 153, 0.05))',
        borderRadius: '50%',
        filter: 'blur(48px)',
        animation: 'pulse 2s ease-in-out infinite 0.5s',
      }} />

      <div style={{ width: '100%', maxWidth: '384px', position: 'relative', zIndex: 10 }}>
        <MovieCard />
      </div>

      <style>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }

        @keyframes pulse {
          0%, 100% { opacity: 0.4; transform: scale(1); }
          50% { opacity: 0.6; transform: scale(1.05); }
        }
      `}</style>
    </div>
  );
}
